import React from 'react';

const VideoItem = ({
  item,
  index,
  onRemove,
  onEdit,
  onMoveUp,
  onMoveDown,
  isFirst,
  isLast,
}) => {
  const { video } = item;

  return (
    <div className="bg-teal-900/70 backdrop-blur-md border border-teal-700 rounded-xl p-4 shadow-md hover:bg-teal-800/70 transition">
      <h3 className="text-lg font-semibold text-white">{video.title}</h3>

      {video.category && (
        <p className="text-teal-200 text-sm mt-1">{video.category}</p>
      )}

      <div className="flex gap-2 mt-4">
        <button
          onClick={onEdit}
          className="bg-teal-600 hover:bg-teal-500 text-white px-2 py-1 rounded text-sm"
        >
          Edit
        </button>
        <button
          onClick={onRemove}
          className="bg-red-500/80 hover:bg-red-500 text-white px-2 py-1 rounded text-sm"
        >
          Remove
        </button>
        <button
          onClick={onMoveUp}
          disabled={isFirst}
          className="bg-slate-600 hover:bg-slate-500 text-white px-2 py-1 rounded text-sm disabled:opacity-40"
        >
          ↑
        </button>
        <button
          onClick={onMoveDown}
          disabled={isLast}
          className="bg-slate-600 hover:bg-slate-500 text-white px-2 py-1 rounded text-sm disabled:opacity-40"
        >
          ↓
        </button>
      </div>
    </div>
  );
};

export default VideoItem;
